/**
 * Resource metadata unit tests — Phase 5-4A-TD.
 *
 * Validates the structure of ResourceMetadata objects
 * as generated by the import handler. No file I/O required.
 */
import { describe, it, expect } from 'vitest';

// Build a mock metadata object matching the import handler's output
function buildMockMetadata(overrides: Record<string, unknown> = {}) {
  return {
    schemaVersion: 1,
    resourceId: 'res_mock_12345',
    vaultId: 'test-vault',
    resourceRelativePath: 'resources/pdf/paper.pdf',
    metadataRelativePath: '.schola/metadata/resources/res_mock_12345.json',
    kind: 'pdf',
    originalName: 'paper.pdf',
    size: 102400,
    importedAt: 1700000000000,
    source: 'imported' as const,
    ...overrides,
  };
}

// ── Core fields ───────────────────────────────────

describe('ResourceMetadata — core fields', () => {
  it('schemaVersion === 1', () => {
    const m = buildMockMetadata();
    expect(m.schemaVersion).toBe(1);
  });

  it('resourceId exists and is string', () => {
    const m = buildMockMetadata();
    expect(typeof m.resourceId).toBe('string');
    expect(m.resourceId.length).toBeGreaterThan(0);
  });

  it('vaultId exists and is string', () => {
    const m = buildMockMetadata();
    expect(typeof m.vaultId).toBe('string');
    expect(m.vaultId.length).toBeGreaterThan(0);
  });

  it('resourceRelativePath is vault-relative', () => {
    const m = buildMockMetadata();
    expect(m.resourceRelativePath).not.toContain(':\\');
    expect(m.resourceRelativePath).not.toContain('/home/');
    expect(m.resourceRelativePath).not.toContain('/Users/');
    expect(m.resourceRelativePath.startsWith('resources/')).toBe(true);
  });

  it('metadataRelativePath is vault-relative', () => {
    const m = buildMockMetadata();
    expect(m.metadataRelativePath).not.toContain(':\\');
    expect(m.metadataRelativePath).not.toContain('/home/');
    expect(m.metadataRelativePath.startsWith('.schola/metadata/resources/')).toBe(true);
  });

  it('kind is valid', () => {
    const validKinds = ['pdf', 'html', 'docx', 'pptx', 'xlsx', 'csv', 'txt', 'image', 'other', 'markdown'];
    const m = buildMockMetadata({ kind: 'pdf' });
    expect(validKinds).toContain(m.kind);
  });

  it('originalName matches expected', () => {
    const m = buildMockMetadata({ originalName: 'paper.pdf' });
    expect(m.originalName).toBe('paper.pdf');
  });

  it('size is number > 0', () => {
    const m = buildMockMetadata();
    expect(typeof m.size).toBe('number');
    expect(m.size).toBeGreaterThan(0);
  });

  it('importedAt is number (timestamp)', () => {
    const m = buildMockMetadata();
    expect(typeof m.importedAt).toBe('number');
    expect(m.importedAt).toBeGreaterThan(1600000000000); // After 2020
  });

  it('source === imported', () => {
    const m = buildMockMetadata();
    expect(m.source).toBe('imported');
  });
});

