// ── Path safety ───────────────────────────────────

describe('ResourceMetadata — path safety', () => {
  it('resourceRelativePath has no system absolute path pattern', () => {
    const m = buildMockMetadata({ resourceRelativePath: 'resources/pdf/paper.pdf' });
    expect(m.resourceRelativePath).not.toContain(':\\');
    expect(m.resourceRelativePath).not.toContain('/home/');
    expect(m.resourceRelativePath).not.toContain('/Users/');
    expect(m.resourceRelativePath).not.toContain('C:');
  });

  it('metadataRelativePath has no system absolute path pattern', () => {
    const m = buildMockMetadata({ metadataRelativePath: '.schola/metadata/resources/res_abc.json' });
    expect(m.metadataRelativePath).not.toContain(':\\');
    expect(m.metadataRelativePath).not.toContain('/home/');
    expect(m.metadataRelativePath).not.toContain('/Users/');
    expect(m.metadataRelativePath).not.toContain('C:');
  });
});

// ── Different resource kinds ──────────────────────

describe('ResourceMetadata — resource kind coverage', () => {
  it('pdf resource', () => {
    const m = buildMockMetadata({
      kind: 'pdf',
      resourceRelativePath: 'resources/pdf/paper.pdf',
    });
    expect(m.kind).toBe('pdf');
    expect(m.resourceRelativePath).toContain('resources/pdf/');
  });

  it('html resource', () => {
    const m = buildMockMetadata({
      kind: 'html',
      resourceRelativePath: 'resources/html/page.html',
    });
    expect(m.kind).toBe('html');
    expect(m.resourceRelativePath).toContain('resources/html/');
  });

  it('docx resource', () => {
    const m = buildMockMetadata({
      kind: 'docx',
      resourceRelativePath: 'resources/docx/report.docx',
    });
    expect(m.kind).toBe('docx');
  });

  it('image resource', () => {
    const m = buildMockMetadata({
      kind: 'image',
      resourceRelativePath: 'resources/images/photo.png',
    });
    expect(m.kind).toBe('image');
  });

  it('csv resource', () => {
    const m = buildMockMetadata({
      kind: 'csv',
      resourceRelativePath: 'resources/csv/data.csv',
    });
    expect(m.kind).toBe('csv');
  });

  it('other resource', () => {
    const m = buildMockMetadata({
      kind: 'other',
      resourceRelativePath: 'resources/other/file.bin',
    });
    expect(m.kind).toBe('other');
  });

  it('markdown resource (unusual but valid)', () => {
    const m = buildMockMetadata({
      kind: 'markdown',
      resourceRelativePath: 'notes/readme.md',
    });
    expect(m.kind).toBe('markdown');
    expect(m.resourceRelativePath).toContain('notes/');
  });
});
